module RefModule (
    input [7:0] A,
    input [7:0] B,
    input [1:0] op,
    output [7:0] out
);

    wire [7:0] add_out = A + B;
    wire [7:0] sub_out = A - B;
    wire [7:0] and_out = A & B;
    wire [7:0] or_out = A | B;

    wire __op_tmp = (op == 2'b00);
    assign out = __op_tmp ? add_out : (op == 2'b01) ? sub_out :
                 (op == 2'b10) ? and_out :
                                 or_out;

endmodule
